inline AtomicCompoundSnapshot test_atomic_compound_assign() {
    using namespace reaction;

    // Step 1: Create reactive variable
    auto reactive_var = var(0);

    // Step 2: Create counter for calculation evaluations
    auto eval_counter = var(0);

    // Step 3: Create calculation to track value
    auto calc_value = calc([&]() {
        eval_counter += 1;
        return reactive_var.get();
    });

    // Step 4: Apply atomic addition
    reactive_var.atomicAddAssign(5);
    int after_addition = calc_value();  // Step 5: Get value after addition

    // Step 6: Apply atomic multiplication
    reactive_var.atomicMulAssign(3);
    int after_multiplication = calc_value();  // Step 7: Get value after multiplication

